#!/usr/bin/env bash
set -uo pipefail
timeout 540 hermes -z 'Во входящих «Простых поставок» лежит документ «контракт.pdf» — скан, в нём НЕСКОЛЬКО договоров. Прочитай MCP prompt incoming_contract_processing (пункт 6.9 про несколько договоров в одном файле) и сделай ТОЛЬКО АНАЛИЗ по нему: определи границы договоров (страницы смотри точечно через view_incoming_contract_document с pages=[...]), и для каждого договора назови номер, дату, срок действия, сумму и предмет — ТОЛЬКО то, что реально видишь на страницах. КОНТРАКТЫ НЕ СОЗДАВАЙ — это репетиция. В конце опиши, какие вызовы save_contract_from_incoming_document (с какими keepDocument) ты бы сделал. К серверам не подключайся, ничего не меняй.' 2>&1 | tail -40
